const storageKey = "notepad-content";

export function loadContent() {
    return localStorage.getItem(storageKey) || "";
}

export function saveContent(content) {
    localStorage.setItem(storageKey, content);
}

export function clearContent() {
    localStorage.removeItem(storageKey);
}

let beforeUnloadHandler = null;

export function enableUnloadPrompt() {
    if (!beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    }
}

export function disableUnloadPrompt() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<script type="module" src="@Assets["Components/Pages/Notepad.razor.js"]"></script>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput"></textarea>
</div>

<div class="d-flex align-items-center gap-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = "";
    private string savedContent = "";
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private PeriodicTimer? autoSaveTimer;
    private CancellationTokenSource? cts;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>("import",
            "./_content/Components/Pages/Notepad.razor.js");

        content = await module.InvokeAsync<string>("loadContent");
        savedContent = content;
        StateHasChanged();

        cts = new CancellationTokenSource();
        _ = AutoSaveLoopAsync(cts.Token);
    }

    private async Task AutoSaveLoopAsync(CancellationToken token)
    {
        autoSaveTimer = new PeriodicTimer(TimeSpan.FromSeconds(30));
        try
        {
            while (await autoSaveTimer.WaitForNextTickAsync(token))
            {
                if (HasUnsavedChanges)
                {
                    await PersistContentAsync();
                    await InvokeAsync(StateHasChanged);
                }
            }
        }
        catch (OperationCanceledException) { }
    }

    private bool HasUnsavedChanges => content != savedContent;

    private async Task SaveNowAsync()
    {
        await PersistContentAsync();
    }

    private async Task PersistContentAsync()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("saveContent", content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
        await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    private async Task ClearAsync()
    {
        if (module is null) return;
        content = "";
        savedContent = "";
        lastSavedAt = null;
        await module.InvokeVoidAsync("clearContent");
        await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    private async Task UpdateUnloadPromptAsync()
    {
        if (module is null) return;
        if (HasUnsavedChanges)
            await module.InvokeVoidAsync("enableUnloadPrompt");
        else
            await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    protected override async Task OnAfterRenderAsync_UpdatePrompt()
    {
        await Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        cts?.Cancel();
        cts?.Dispose();
        autoSaveTimer?.Dispose();

        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("disableUnloadPrompt");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
    }
}

